from vex import Guardrail

async def vex_email_verification(state: EmailState) -> EmailState:
    guards = Guardrail('email-safety-suite')

    verification_results = await guards.run([
        {
            'name': 'pii_filtering',
            'input': state['draft'],
            'rules': ['no-ssn', 'no-credit-cards', 'no-personal-identifiers']
        },
        {
            'name': 'tone_appropriateness',
            'input': state['draft'],
            'threshold': 8.0,
            'category': 'professional'
        },
        {
            'name': 'recipient_validation',
            'input': state['recipients'],
            'rules': ['valid-email-format', 'no-external-unless-approved']
        }
    ])

    state['verification_passed'] = all(result.passed for result in verification_results)

    if not state['verification_passed']:
        state['draft'] = "Email blocked by Vex safety checks"
        return {'next': 'human_review'}

    return state

workflow.add_node('vex_verification', vex_email_verification)

# Route to Vex before final send
def should_verify(state: EmailState) -> str:
    return 'vex_verification' if state['human_approved'] else 'human_review'
